export type StackFoundryAppConfig = {
  name: string;
  description: string;
  supportEmail: string;
  marketingUrl: string;
  dashboardUrl: string;
};

export const stackfoundryAppConfig: StackFoundryAppConfig = {
  name: "Acme SaaS",
  description: "A production SaaS application assembled from editable source modules.",
  supportEmail: "support@example.com",
  marketingUrl: "/launch",
  dashboardUrl: "/dashboard",
};

export const stackfoundryLaunchChecklist = [
  "Choose account mode: personal, team, or hybrid.",
  "Install database, auth, billing, and API modules intentionally.",
  "Copy generated env examples into your secret manager.",
  "Run migrations only after reviewing schema slices.",
  "Run module checklists before enabling production traffic.",
] as const;

export type StackFoundryNavItem = {
  label: string;
  href: string;
  description: string;
};

export const stackfoundryPrimaryNav: StackFoundryNavItem[] = [
  {
    label: "Dashboard",
    href: "/dashboard",
    description: "Overview, setup progress, and launch checks.",
  },
  {
    label: "Billing",
    href: "/billing",
    description: "Plans, invoices, portal, usage, and entitlements.",
  },
  {
    label: "Developers",
    href: "/api-keys",
    description: "API keys, webhooks, API docs, and usage visibility.",
  },
  {
    label: "Settings",
    href: "/settings/account",
    description: "Account, workspace, security, and notification settings.",
  },
];

import type { ReactNode } from "react";

import { stackfoundryAppConfig } from "@/lib/stackfoundry/app-config";
import { stackfoundryPrimaryNav } from "@/lib/stackfoundry/app-navigation";

export function StackFoundryAppShell({ children }: { children: ReactNode }) {
  return (
    <div className="min-h-screen bg-background text-foreground">
      <aside className="fixed inset-y-0 hidden w-64 border-r bg-card p-4 lg:block">
        <a className="font-semibold tracking-tight" href={stackfoundryAppConfig.dashboardUrl}>
          {stackfoundryAppConfig.name}
        </a>
        <nav className="mt-6 grid gap-1">
          {stackfoundryPrimaryNav.map((item) => (
            <a
              className="rounded-md px-3 py-2 text-sm text-muted-foreground hover:bg-muted"
              href={item.href}
              key={item.href}
            >
              {item.label}
            </a>
          ))}
        </nav>
      </aside>
      <div className="lg:pl-64">
        <header className="sticky top-0 z-10 border-b bg-background/90 px-4 py-3 backdrop-blur">
          <div className="flex items-center justify-between gap-4">
            <a className="font-medium lg:hidden" href={stackfoundryAppConfig.dashboardUrl}>
              {stackfoundryAppConfig.name}
            </a>
            <p className="hidden text-sm text-muted-foreground sm:block">
              {stackfoundryAppConfig.description}
            </p>
            <a
              className="text-sm text-muted-foreground hover:text-foreground"
              href={stackfoundryAppConfig.marketingUrl}
            >
              Launch page
            </a>
          </div>
        </header>
        <main className="p-4 md:p-6">{children}</main>
      </div>
    </div>
  );
}

import { stackfoundryAppConfig, stackfoundryLaunchChecklist } from "@/lib/stackfoundry/app-config";

const featureRows = [
  "Accounts, workspace settings, and tenant boundaries",
  "Billing, entitlements, usage, credits, and invoices",
  "API keys, webhooks, developer docs, and usage dashboards",
  "Operations, audit logs, background jobs, and health checks",
];

export default function LaunchPage() {
  return (
    <main className="mx-auto flex min-h-screen max-w-6xl flex-col gap-12 px-6 py-16">
      <section className="max-w-3xl space-y-5">
        <p className="text-sm font-medium text-muted-foreground">Launch-ready SaaS shell</p>
        <h1 className="text-4xl font-semibold tracking-tight md:text-6xl">
          {stackfoundryAppConfig.name}
        </h1>
        <p className="text-lg text-muted-foreground">{stackfoundryAppConfig.description}</p>
        <div className="flex flex-wrap gap-3">
          <a
            className="rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground"
            href={stackfoundryAppConfig.dashboardUrl}
          >
            Open dashboard
          </a>
          <a
            className="rounded-md border px-4 py-2 text-sm font-medium"
            href={`mailto:${stackfoundryAppConfig.supportEmail}`}
          >
            Contact support
          </a>
        </div>
      </section>
      <section className="grid gap-4 md:grid-cols-2">
        {featureRows.map((feature) => (
          <div className="rounded-lg border bg-card p-5" key={feature}>
            <p className="text-sm text-muted-foreground">{feature}</p>
          </div>
        ))}
      </section>
      <section className="rounded-lg border bg-card p-5">
        <h2 className="font-medium">Before production</h2>
        <ul className="mt-4 grid gap-2 text-sm text-muted-foreground">
          {stackfoundryLaunchChecklist.map((item) => (
            <li key={item}>{item}</li>
          ))}
        </ul>
      </section>
    </main>
  );
}

import { StackFoundryAppShell } from "@/components/stackfoundry/app-shell";
import { stackfoundryLaunchChecklist } from "@/lib/stackfoundry/app-config";
import { stackfoundryPrimaryNav } from "@/lib/stackfoundry/app-navigation";

const stats = [
  ["Modules", "Source-owned capabilities"],
  ["Env", "Explicit setup notes"],
  ["Checks", "Review before production"],
];

export default function DashboardPage() {
  return (
    <StackFoundryAppShell>
      <div className="grid gap-6">
        <section className="rounded-lg border bg-card p-6">
          <p className="text-sm font-medium text-muted-foreground">Dashboard</p>
          <h1 className="mt-2 text-2xl font-semibold tracking-tight">SaaS setup overview</h1>
          <p className="mt-2 max-w-2xl text-sm text-muted-foreground">
            Use this page as the first authenticated surface after installing the base shell. Add
            auth, billing, database, API, and operations modules as your product shape becomes
            clear.
          </p>
        </section>
        <section className="grid gap-4 md:grid-cols-3">
          {stats.map(([title, description]) => (
            <div className="rounded-lg border bg-card p-5" key={title}>
              <h2 className="font-medium">{title}</h2>
              <p className="mt-2 text-sm text-muted-foreground">{description}</p>
            </div>
          ))}
        </section>
        <section className="grid gap-4 lg:grid-cols-[1fr_1.2fr]">
          <div className="rounded-lg border bg-card p-5">
            <h2 className="font-medium">Primary navigation</h2>
            <div className="mt-4 grid gap-3">
              {stackfoundryPrimaryNav.map((item) => (
                <a
                  className="rounded-md border p-3 text-sm hover:bg-muted"
                  href={item.href}
                  key={item.href}
                >
                  <span className="font-medium">{item.label}</span>
                  <span className="mt-1 block text-muted-foreground">{item.description}</span>
                </a>
              ))}
            </div>
          </div>
          <div className="rounded-lg border bg-card p-5">
            <h2 className="font-medium">Launch checklist</h2>
            <ul className="mt-4 grid gap-3 text-sm text-muted-foreground">
              {stackfoundryLaunchChecklist.map((item) => (
                <li key={item}>{item}</li>
              ))}
            </ul>
          </div>
        </section>
      </div>
    </StackFoundryAppShell>
  );
}
